def compress_rle(s):
    if not s:
        return ""
    result = []
    current = s[0]
    count = 1
    for ch in s[1:]:
        if ch == current:
            count += 1
        else:
            result.append(current + str(count))
            current = ch
            count = 1
    result.append(current + str(count))
    return "".join(result)
